<?php require_once __DIR__.'/../../middleware/bootstrap.php';$u=user();$amount=(float)($_POST['amount']??0);if($amount<=0)out(['error'=>'Invalid amount'],422);$proof=null;if(isset($_FILES['proof'])){$ext=pathinfo($_FILES['proof']['name'],PATHINFO_EXTENSION);if(!in_array(strtolower($ext),['jpg','jpeg','png','pdf']))out(['error'=>'Invalid proof'],422);$proof='uploads/'.bin2hex(random_bytes(8)).'.'.$ext;move_uploaded_file($_FILES['proof']['tmp_name'],__DIR__.'/../../'.$proof);} $st=db()->prepare('insert into wallet_requests(user_id,amount,method,transaction_id,proof_path,status,created_at)values(?,?,?,?,?,"pending",now())');$st->execute([$u['id'],$amount,clean($_POST['method']??'bank'),clean($_POST['transaction_id']??''),$proof]);out(['ok'=>true,'id'=>db()->lastInsertId()]);
